package com.evernorth.smartemp.controller; import com.evernorth.smartemp.dto.AuthDtos.*; import com.evernorth.smartemp.service.AuthService; import jakarta.validation.Valid; import lombok.RequiredArgsConstructor; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/auth") @RequiredArgsConstructor public class AuthController{private final AuthService s;@PostMapping("/login")public ResponseEntity<LoginResponse> login(@Valid @RequestBody LoginRequest r){return ResponseEntity.ok(s.login(r));}@PostMapping("/register")public ResponseEntity<String> register(@Valid @RequestBody RegisterRequest r){s.register(r);return ResponseEntity.ok("Registration successful");}}
